import{_ as i,o,c as t,ae as l}from"./chunks/framework.fcrFxRdA.js";const h=JSON.parse('{"title":"Product Requirements Document","description":"","frontmatter":{},"headers":[],"relativePath":"prd.md","filePath":"prd.md"}'),a={name:"prd.md"};function r(n,e,s,c,u,d){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="product-requirements-document" tabindex="-1">Product Requirements Document <a class="header-anchor" href="#product-requirements-document" aria-label="Permalink to &quot;Product Requirements Document&quot;">​</a></h1><p><strong>Project:</strong> React Icons to SVG Exporter<br><strong>Owner:</strong> Frederic Jacquet<br><strong>Repo:</strong> <code>fjacquet/icons</code></p><hr><h2 id="_1-overview" tabindex="-1">1. Overview <a class="header-anchor" href="#_1-overview" aria-label="Permalink to &quot;1. Overview&quot;">​</a></h2><p>The <strong>React Icons to SVG Exporter</strong> is a small web tool that renders React-based icon components to <strong>standalone SVG files</strong> so they can be reused in <strong>presentations</strong> (PowerPoint, Keynote, Google Slides, etc.).</p><p>The app is built with <strong>React</strong> and is <strong>published via GitHub Pages</strong> for easy hosting and distribution.</p><hr><h2 id="_2-goals-non‐goals" tabindex="-1">2. Goals &amp; Non‑Goals <a class="header-anchor" href="#_2-goals-non‐goals" aria-label="Permalink to &quot;2. Goals &amp; Non‑Goals&quot;">​</a></h2><h3 id="_2-1-goals" tabindex="-1">2.1 Goals <a class="header-anchor" href="#_2-1-goals" aria-label="Permalink to &quot;2.1 Goals&quot;">​</a></h3><ul><li>Provide a <strong>simple UI</strong> to browse available icons and export them as SVG files.</li><li>Allow users to <strong>customize basic properties</strong> (size, color, background) before export.</li><li>Support <strong>single and bulk download</strong> of icons as SVG and/or ZIP archive.</li><li>Ensure <strong>consistent, clean SVG output</strong> suitable for use in presentation tools.</li><li>Automate <strong>build, lint, test, and deploy</strong> to GitHub Pages through CI.</li><li>Keep the implementation <strong>small, maintainable, and contributor‑friendly</strong>.</li></ul><h3 id="_2-2-non‐goals" tabindex="-1">2.2 Non‑Goals <a class="header-anchor" href="#_2-2-non‐goals" aria-label="Permalink to &quot;2.2 Non‑Goals&quot;">​</a></h3><ul><li>Full-featured vector editor (no complex shape editing beyond simple properties).</li><li>Managing user accounts or persistence beyond the browser (no backend).</li><li>In-app slide editor or presentation builder — the focus is <strong>export</strong>, not editing slides.</li><li>Supporting non-SVG formats (PNG export can be a future enhancement).</li></ul><hr><h2 id="_3-users-use-cases" tabindex="-1">3. Users &amp; Use Cases <a class="header-anchor" href="#_3-users-use-cases" aria-label="Permalink to &quot;3. Users &amp; Use Cases&quot;">​</a></h2><h3 id="_3-1-target-users" tabindex="-1">3.1 Target Users <a class="header-anchor" href="#_3-1-target-users" aria-label="Permalink to &quot;3.1 Target Users&quot;">​</a></h3><ul><li><strong>Developers / engineers</strong> who already use React icon libraries and need to export icons for non-web contexts.</li><li><strong>Solution architects / pre‑sales</strong> who frequently build decks and need consistent iconography.</li><li><strong>Designers</strong> who want to quickly grab an SVG variant of an existing React icon.</li></ul><h3 id="_3-2-key-use-cases" tabindex="-1">3.2 Key Use Cases <a class="header-anchor" href="#_3-2-key-use-cases" aria-label="Permalink to &quot;3.2 Key Use Cases&quot;">​</a></h3><ol><li><p><strong>Quick single icon export</strong></p><ul><li>User navigates to the app.</li><li>Searches or browses for an icon.</li><li>Adjusts color/size.</li><li>Downloads a single SVG file and drags it into a presentation.</li></ul></li><li><p><strong>Batch export a set of icons</strong></p><ul><li>User selects multiple icons (e.g., all “infrastructure” icons).</li><li>Applies shared styling (color, size).</li><li>Downloads a ZIP containing all selected SVGs.</li></ul></li><li><p><strong>Consistent styling for a deck</strong></p><ul><li>User defines a theme (primary color, default size).</li><li>Applies this theme to all exported icons for a specific deck.</li><li>Ensures consistent look &amp; feel across slides.</li></ul></li></ol><hr><h2 id="_4-product-scope" tabindex="-1">4. Product Scope <a class="header-anchor" href="#_4-product-scope" aria-label="Permalink to &quot;4. Product Scope&quot;">​</a></h2><h3 id="_4-1-mvp" tabindex="-1">4.1 MVP <a class="header-anchor" href="#_4-1-mvp" aria-label="Permalink to &quot;4.1 MVP&quot;">​</a></h3><ul><li>UI listing icons from a predefined React icon set (or multiple sets).</li><li>Search/filter by icon name and/or category.</li><li>Inline preview of selected icon.</li><li>Basic styling controls: <ul><li><strong>Size</strong> (px)</li><li><strong>Color</strong> (hex/RGB picker or presets)</li><li><strong>Background</strong> (transparent vs solid, optional)</li></ul></li><li>Export actions: <ul><li>Download <strong>single SVG</strong>.</li><li>Download <strong>multiple SVGs as ZIP</strong>.</li></ul></li><li>Static deployment via <strong>GitHub Pages</strong> (built from <code>main</code>).</li></ul><h3 id="_4-2-nice‐to‐have-post‐mvp" tabindex="-1">4.2 Nice‑to‑Have (post‑MVP) <a class="header-anchor" href="#_4-2-nice‐to‐have-post‐mvp" aria-label="Permalink to &quot;4.2 Nice‑to‑Have (post‑MVP)&quot;">​</a></h3><ul><li>Favorite / pinned icons (stored in localStorage).</li><li>Theme presets (e.g., “Light”, “Dark”, “Dell‑blue”).</li><li>Copy SVG to clipboard.</li><li>PNG export (via client-side rasterization).</li><li>Multi-library support (e.g., react-icons, custom icon packs).</li></ul><hr><h2 id="_5-functional-requirements" tabindex="-1">5. Functional Requirements <a class="header-anchor" href="#_5-functional-requirements" aria-label="Permalink to &quot;5. Functional Requirements&quot;">​</a></h2><h3 id="_5-1-icon-catalog" tabindex="-1">5.1 Icon Catalog <a class="header-anchor" href="#_5-1-icon-catalog" aria-label="Permalink to &quot;5.1 Icon Catalog&quot;">​</a></h3><ul><li><strong>FR-1:</strong> The system <strong>shall display</strong> a grid/list of available icons with: <ul><li>Icon preview</li><li>Icon name</li><li>Library/category (if applicable)</li></ul></li><li><strong>FR-2:</strong> The user <strong>shall be able to</strong> search icons by name (case-insensitive).</li><li><strong>FR-3:</strong> The user <strong>shall be able to</strong> filter icons by category/library (if defined).</li></ul><h3 id="_5-2-icon-preview-customization" tabindex="-1">5.2 Icon Preview &amp; Customization <a class="header-anchor" href="#_5-2-icon-preview-customization" aria-label="Permalink to &quot;5.2 Icon Preview &amp; Customization&quot;">​</a></h3><ul><li><strong>FR-4:</strong> When an icon is selected, a <strong>preview panel</strong> shall display a larger version.</li><li><strong>FR-5:</strong> The user <strong>shall be able to</strong> adjust: <ul><li>Size (numeric input + slider or presets).</li><li>Color (color picker or fixed palette).</li><li>Background (transparent vs solid).</li></ul></li><li><strong>FR-6:</strong> Changes in settings <strong>shall update</strong> the preview in real time.</li></ul><h3 id="_5-3-export" tabindex="-1">5.3 Export <a class="header-anchor" href="#_5-3-export" aria-label="Permalink to &quot;5.3 Export&quot;">​</a></h3><ul><li><strong>FR-7:</strong> The user <strong>shall be able to</strong> download a <strong>single icon</strong> as a <code>.svg</code> file reflecting current settings.</li><li><strong>FR-8:</strong> The user <strong>shall be able to</strong> select <strong>multiple icons</strong> and export them as: <ul><li>Individual <code>.svg</code> files</li><li>Optional <code>.zip</code> archive containing all SVGs</li></ul></li><li><strong>FR-9:</strong> Generated SVG files <strong>shall not depend</strong> on React or JavaScript at runtime (pure SVG).</li></ul><h3 id="_5-4-project-configuration-quality" tabindex="-1">5.4 Project Configuration &amp; Quality <a class="header-anchor" href="#_5-4-project-configuration-quality" aria-label="Permalink to &quot;5.4 Project Configuration &amp; Quality&quot;">​</a></h3><ul><li><strong>FR-10:</strong> The project <strong>shall include</strong> scripts in <code>package.json</code> for: <ul><li><code>build</code></li><li><code>test</code></li><li><code>lint</code></li><li><code>format</code> (if using Prettier)</li></ul></li><li><strong>FR-11:</strong> The repository <strong>shall include</strong>: <ul><li><code>README.md</code> with usage, development setup, and deployment info.</li><li><code>CONTRIBUTING.md</code> with contribution flow and checks to run.</li><li><code>LICENSE</code> file.</li></ul></li><li><strong>FR-12:</strong> The app <strong>shall be</strong> a static React site that can be built with <code>npm run build</code> (or equivalent) and deployed to GitHub Pages.</li></ul><hr><h2 id="_6-non‐functional-requirements" tabindex="-1">6. Non‑Functional Requirements <a class="header-anchor" href="#_6-non‐functional-requirements" aria-label="Permalink to &quot;6. Non‑Functional Requirements&quot;">​</a></h2><h3 id="_6-1-performance" tabindex="-1">6.1 Performance <a class="header-anchor" href="#_6-1-performance" aria-label="Permalink to &quot;6.1 Performance&quot;">​</a></h3><ul><li><strong>NFR-1:</strong> Initial load time on GitHub Pages should be &lt; 3 seconds on a typical broadband connection.</li><li><strong>NFR-2:</strong> Icon rendering and property updates should feel instantaneous (&lt; 100ms) for typical icon sets (&lt; 1000 icons).</li></ul><h3 id="_6-2-compatibility" tabindex="-1">6.2 Compatibility <a class="header-anchor" href="#_6-2-compatibility" aria-label="Permalink to &quot;6.2 Compatibility&quot;">​</a></h3><ul><li><strong>NFR-3:</strong> Support current versions of major desktop browsers: <ul><li>Chrome</li><li>Firefox</li><li>Edge</li><li>Safari</li></ul></li><li><strong>NFR-4:</strong> SVG exports should render correctly in: <ul><li>PowerPoint (Windows + macOS)</li><li>Keynote</li><li>Google Slides</li></ul></li></ul><h3 id="_6-3-reliability" tabindex="-1">6.3 Reliability <a class="header-anchor" href="#_6-3-reliability" aria-label="Permalink to &quot;6.3 Reliability&quot;">​</a></h3><ul><li><strong>NFR-5:</strong> CI should block merges to <code>main</code> if <strong>build, tests, or lint</strong> fail.</li><li><strong>NFR-6:</strong> CI + GitHub Pages deployment should complete in &lt; 5 minutes under normal conditions.</li></ul><hr><h2 id="_7-architecture-tech-stack" tabindex="-1">7. Architecture &amp; Tech Stack <a class="header-anchor" href="#_7-architecture-tech-stack" aria-label="Permalink to &quot;7. Architecture &amp; Tech Stack&quot;">​</a></h2><h3 id="_7-1-technologies" tabindex="-1">7.1 Technologies <a class="header-anchor" href="#_7-1-technologies" aria-label="Permalink to &quot;7.1 Technologies&quot;">​</a></h3><ul><li><strong>Frontend:</strong> React (Create React App, Vite, or similar).</li><li><strong>Styling:</strong> CSS/SCSS or CSS-in-JS (TBD).</li><li><strong>Icons:</strong> React icon components imported from: <ul><li>A chosen library (<code>react-icons</code>, custom internal components, etc.).</li></ul></li><li><strong>Build &amp; Deployment:</strong><ul><li>Node.js/npm scripts.</li><li>GitHub Actions for CI and deployment.</li><li>GitHub Pages as hosting.</li></ul></li></ul><h3 id="_7-2-high‐level-flow" tabindex="-1">7.2 High‑Level Flow <a class="header-anchor" href="#_7-2-high‐level-flow" aria-label="Permalink to &quot;7.2 High‑Level Flow&quot;">​</a></h3><ol><li>User opens GitHub Pages URL.</li><li>React app loads icon catalog (static import or generated manifest).</li><li>User searches/selects icons and tweaks settings.</li><li>For export, React component is rendered to SVG markup and: <ul><li>Blob is created client-side for download.</li><li>For batch, multiple SVGs are zipped (JS library) and offered as a single download.</li></ul></li></ol><hr><h2 id="_8-ci-cd-quality-gates" tabindex="-1">8. CI/CD &amp; Quality Gates <a class="header-anchor" href="#_8-ci-cd-quality-gates" aria-label="Permalink to &quot;8. CI/CD &amp; Quality Gates&quot;">​</a></h2><h3 id="_8-1-ci" tabindex="-1">8.1 CI <a class="header-anchor" href="#_8-1-ci" aria-label="Permalink to &quot;8.1 CI&quot;">​</a></h3><ul><li><strong>CI-1:</strong> On every <strong>pull request</strong> and <strong>push to main</strong>: <ul><li>Install dependencies (with cache).</li><li>Run <code>npm run lint</code>.</li><li>Run <code>npm test</code> (or equivalent).</li><li>Run <code>npm run build</code>.</li></ul></li><li><strong>CI-2:</strong> If any step fails, the workflow fails and prevents merge.</li></ul><h3 id="_8-2-security-dependency-checks" tabindex="-1">8.2 Security &amp; Dependency Checks <a class="header-anchor" href="#_8-2-security-dependency-checks" aria-label="Permalink to &quot;8.2 Security &amp; Dependency Checks&quot;">​</a></h3><ul><li><strong>CI-3:</strong> Run a dependency security scan (e.g., <code>npm audit --production</code>, or GitHub-native <code>dependabot</code>).</li><li><strong>CI-4:</strong> Optionally enable GitHub <strong>Code Scanning</strong> / <strong>Secret Scanning</strong> for the repo.</li></ul><h3 id="_8-3-badges" tabindex="-1">8.3 Badges <a class="header-anchor" href="#_8-3-badges" aria-label="Permalink to &quot;8.3 Badges&quot;">​</a></h3><ul><li><strong>CI-5:</strong> README should display badges for: <ul><li>Build status (GitHub Actions).</li><li>License.</li><li>(Optional) Test coverage.</li></ul></li></ul><hr><h2 id="_9-ux-ui-requirements" tabindex="-1">9. UX &amp; UI Requirements <a class="header-anchor" href="#_9-ux-ui-requirements" aria-label="Permalink to &quot;9. UX &amp; UI Requirements&quot;">​</a></h2><ul><li><strong>UX-1:</strong> Clean, minimal layout: <ul><li>Left: icon grid and filters.</li><li>Right: preview &amp; settings panel.</li></ul></li><li><strong>UX-2:</strong> Icons should show name on hover and/or below the glyph.</li><li><strong>UX-3:</strong> Selected icons should be visually highlighted.</li><li><strong>UX-4:</strong> Export buttons (single and bulk) should be clearly labeled and always visible when there is a selection.</li><li><strong>UX-5:</strong> Show lightweight feedback: <ul><li>Toast/snackbar on successful download.</li><li>Error indication if something goes wrong.</li></ul></li></ul><hr><h2 id="_10-metrics-success-criteria" tabindex="-1">10. Metrics &amp; Success Criteria <a class="header-anchor" href="#_10-metrics-success-criteria" aria-label="Permalink to &quot;10. Metrics &amp; Success Criteria&quot;">​</a></h2><ul><li><strong>M-1:</strong> Ability to export a <strong>single icon</strong> as SVG in &lt; 5 clicks from initial page load.</li><li><strong>M-2:</strong> Ability to export <strong>N icons</strong> (&lt;= 20) as a ZIP in &lt; 10 clicks.</li><li><strong>M-3:</strong> No CI‑breaking issues on <code>main</code> for a rolling 30‑day period.</li><li><strong>M-4:</strong> (If using analytics) Basic usage metrics: <ul><li>Number of sessions.</li><li>Number of exports per session.</li></ul></li></ul><hr><h2 id="_11-risks-open-questions" tabindex="-1">11. Risks &amp; Open Questions <a class="header-anchor" href="#_11-risks-open-questions" aria-label="Permalink to &quot;11. Risks &amp; Open Questions&quot;">​</a></h2><h3 id="_11-1-risks" tabindex="-1">11.1 Risks <a class="header-anchor" href="#_11-1-risks" aria-label="Permalink to &quot;11.1 Risks&quot;">​</a></h3><ul><li>Large icon sets may impact initial load or memory usage.</li><li>Differences in how presentation tools interpret certain SVG features (e.g., filters, gradients).</li></ul><h3 id="_11-2-open-questions" tabindex="-1">11.2 Open Questions <a class="header-anchor" href="#_11-2-open-questions" aria-label="Permalink to &quot;11.2 Open Questions&quot;">​</a></h3><ul><li>Which icon library/libraries will be the <strong>initial focus</strong>?</li><li>Do we need <strong>PNG export</strong> for environments that don’t handle SVG well?</li><li>Should we support <strong>multi-color</strong> icons with per-part customization or keep it simple (single fill color)?</li></ul><hr><h2 id="_12-roadmap-high‐level" tabindex="-1">12. Roadmap (High‑Level) <a class="header-anchor" href="#_12-roadmap-high‐level" aria-label="Permalink to &quot;12. Roadmap (High‑Level)&quot;">​</a></h2><ol><li><strong>MVP</strong><ul><li>Basic React app with catalog, preview, customization, and SVG export.</li><li>Initial CI pipeline and deployment to GitHub Pages.</li></ul></li><li><strong>Polish</strong><ul><li>Better filters, UI improvements, favorites.</li><li>Documentation, badges, contribution guidelines.</li></ul></li><li><strong>Extensions</strong><ul><li>PNG export, theming, multi-library support, richer customization.</li></ul></li></ol>',71)])])}const p=i(a,[["render",r]]);export{h as __pageData,p as default};
